import { useState, useEffect } from 'react';
import API from '../../services/axios';

function AllBookings() {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    API.get('/bookings/all/bookings')
      .then(res => setBookings(res.data.bookings || []))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  if (loading) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '100vh', background: '#fdf6f3' }}>
      <p style={{ color: '#c9a99a' }}>Loading bookings...</p>
    </div>
  );

  return (
    <div style={{ padding: '2rem', background: '#fdf6f3', minHeight: '100vh', fontFamily: "'DM Sans', sans-serif" }}>
      <div style={{ marginBottom: '1.5rem' }}>
        <h1 style={{ fontSize: '1.6rem', fontWeight: '700', color: '#2d1f1f', margin: 0, fontFamily: "'Cormorant Garamond', serif" }}>All Bookings</h1>
        <p style={{ color: '#a08880', fontSize: '0.84rem', marginTop: '4px' }}>{bookings.length} total bookings</p>
      </div>

      <div style={{ background: 'white', borderRadius: '16px', boxShadow: '0 2px 12px rgba(201,169,154,0.1)', border: '1px solid #f5e8e3', overflow: 'hidden' }}>
        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.84rem' }}>
            <thead>
              <tr style={{ background: 'linear-gradient(135deg, #c9a99a, #b8887a)' }}>
                {['USER', 'EMAIL', 'EVENT', 'SEATS', 'AMOUNT', 'BOOKING STATUS'].map(h => (
                  <th key={h} style={{ padding: '14px 16px', textAlign: 'left', color: 'white', fontWeight: '600', fontSize: '0.72rem', letterSpacing: '1px' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {bookings.length === 0 ? (
                <tr><td colSpan={6} style={{ padding: '3rem', textAlign: 'center', color: '#a08880' }}>
                  <div style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>🌷</div>No bookings found
                </td></tr>
              ) : bookings.map((b, i) => (
                <tr key={b._id} style={{ borderBottom: '1px solid #f5e8e3', background: i % 2 === 0 ? 'white' : '#fffaf8' }}>
                  <td style={{ padding: '14px 16px', fontWeight: '600', color: '#2d1f1f' }}>{b.user?.name}</td>
                  <td style={{ padding: '14px 16px', color: '#a08880' }}>{b.user?.email}</td>
                  <td style={{ padding: '14px 16px', color: '#6b5a55' }}>{b.event?.name}</td>
                  <td style={{ padding: '14px 16px', color: '#6b5a55', textAlign: 'center' }}>{b.numberOfTickets}</td>
                  <td style={{ padding: '14px 16px', fontWeight: '700', color: '#c9a99a' }}>₹{b.totalAmount}</td>
                  <td style={{ padding: '14px 16px' }}>
                    <span style={{
                      padding: '5px 14px', borderRadius: '20px', fontSize: '0.72rem', fontWeight: '600',
                      background: b.status === 'confirmed' ? '#edf5f0' : b.status === 'pending' ? '#fef9ec' : '#fdeee9',
                      color: b.status === 'confirmed' ? '#4a8a6a' : b.status === 'pending' ? '#8a7040' : '#a05040'
                    }}>{b.status}</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
export default AllBookings;
